module top_module(
    input [15:0] input16,
    output [7:0] output8
);wire [7:0] upper_half;
wire [7:0] last8;

assign upper_half = input16[15:8];
assign last8 = input16[7:0];

// ripple carry adder
wire [8:0] sum;
assign sum = {1'b0, upper_half} + {1'b0, last8};

assign output8 = sum[7:0];

endmodule
